ps.pstext:
if !IsFeatureImplemented(FEAT_SVE) || !IsFeatureImplemented(FEAT_CPA) then
    EndOfDecode(Decode_UNDEF);
end;
let g : integer =  UInt(Pg);
let dn : integer = UInt(Zdn);
let m : integer =  UInt(Zm);

CheckNonStreamingSVEEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let elements : integer = VL DIV 64;
let mask : bits(PL) = P{}(g);
let operand1 : bits(VL) = Z{}(dn);
let operand2 : bits(VL) = if AnyActiveElement{PL}(mask, 64) then Z{VL}(m) else Zeros{VL};
var result : bits(VL);

for e = 0 to elements-1 do
    let element1 : bits(64) = operand1[e*:64];
    let element2 : bits(64) = operand2[e*:64];
    if ActivePredicateElement{PL}(mask, e, 64) then
        let res : bits(64) = element1 - element2;
        result[e*:64] = PointerAddCheck(res, element1);
    else
        result[e*:64] = operand1[e*:64];
    end;

    Z{VL}(dn) = result;
end;
